content.content:
// Modal HTML básico
ogComponent('modal').open('<h4>Hola!</h4><p>Contenido HTML</p>', {
  html: true,
  title: 'Mi Modal'
});

// Con footer personalizado
ogComponent('modal').open('<p>Contenido</p>', {
  html: true,
  title: 'Confirmación',
  footer: '<button class="btn btn-success" onclick="ogComponent(\'modal\').closeAll()">Aceptar</button>'
});

// Compacto sin footer
ogComponent('modal').open('<p>Mensaje</p>', {
  html: true,
  title: 'Aviso',
  width: '400px',
  maxWidth: '400px',
  showFooter: false
});

// Abrir un formulario JSON dentro de un modal
// Formato: 'extension|forms/nombre-del-formulario'
ogComponent('modal').open('ejemplos|forms/formularios/form-inputs-normales', {
  title: '📝 Formulario en Modal',
  width: '680px',
  maxWidth: '720px'
});

// Opciones de efecto: 'slide-up' | 'fade-scale' | 'slide-right'
ogComponent('modal').open('<p>Contenido</p>', {
  html: true,
  title: 'Modal animado',
  effect: 'fade-scale'
});

// Pequeño
ogComponent('modal').open(resource, { width: '380px', maxWidth: '400px' });

// Mediano (valores por defecto)
ogComponent('modal').open(resource, {});

// Grande
ogComponent('modal').open(resource, { width: '95%', maxWidth: '1400px' });

// Abrir múltiples modales
ogComponent('modal').open(resource1, { title: 'Modal 1' });
ogComponent('modal').open(resource2, { title: 'Modal 2' });

// Cerrar todos
ogComponent('modal').closeAll();
